import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { ProductCard } from './components/ProductCard';
import { Cart } from './components/Cart';
import { AIAssistant } from './components/AIAssistant';
import { PRODUCTS } from './constants';
import { Product, CartItem } from './types';

const App: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const addToCart = (product: Product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
    ).filter(item => item.quantity > 0));
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen selection:bg-emerald-200 selection:text-emerald-900">
      {/* Header */}
      <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? 'py-4' : 'py-8'}`}>
        <div className="container mx-auto px-6">
          <div className={`glass rounded-[2rem] px-8 py-4 flex justify-between items-center transition-all duration-500 ${scrolled ? 'shadow-lg border-stone-200/50' : 'border-transparent bg-transparent'}`}>
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-emerald-900 rounded-xl flex items-center justify-center text-white font-black text-xl italic shadow-lg shadow-emerald-900/20">J</div>
              <span className="text-2xl font-black tracking-tight text-emerald-950">JabaTamu</span>
            </div>

            <div className="hidden md:flex items-center gap-8 text-sm font-semibold text-stone-600">
              <a href="#shop" className="hover:text-emerald-800 transition-colors">Our Juices</a>
              <a href="#benefits" className="hover:text-emerald-800 transition-colors">Benefits</a>
              <a href="#about" className="hover:text-emerald-800 transition-colors">Origins</a>
            </div>

            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 text-stone-900 hover:text-emerald-800 transition-colors group"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="8" cy="21" r="1"/><circle cx="19" cy="21" r="1"/><path d="M2.05 2.05h2l2.66 12.42a2 2 0 0 0 2 1.58h9.78a2 2 0 0 0 1.95-1.57l1.65-7.43H5.12"/></svg>
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-emerald-700 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full ring-4 ring-stone-50/50 group-hover:scale-110 transition-transform">
                  {cartCount}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative pt-48 pb-20 overflow-hidden">
        <div className="absolute top-0 right-0 -z-10 w-[800px] h-[800px] bg-emerald-100 rounded-full blur-[120px] -mr-96 -mt-96 opacity-60"></div>
        <div className="absolute bottom-0 left-0 -z-10 w-[600px] h-[600px] bg-yellow-50 rounded-full blur-[100px] -ml-48 -mb-48 opacity-40"></div>

        <div className="container mx-auto px-6">
          <div className="max-w-4xl mx-auto text-center space-y-8">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-50 border border-emerald-100 rounded-full text-emerald-800 text-sm font-bold tracking-wide uppercase">
              <span className="flex h-2 w-2 rounded-full bg-emerald-500 animate-pulse"></span>
              Freshly Pressed Khat Infusions
            </div>
            <h1 className="text-6xl md:text-8xl font-black text-stone-900 leading-[1.1] tracking-tight">
              Natural Energy <br /> 
              <span className="text-emerald-900 italic">Reimagined.</span>
            </h1>
            <p className="text-xl text-stone-500 max-w-2xl mx-auto font-medium">
              Premium botanical juices crafted from sun-drenched fresh khat leaves and exotic island fruits. Pure focus, zero synthetic junk.
            </p>
            <div className="flex flex-col sm:flex-row items-center justify-center gap-4 pt-4">
              <a href="#shop" className="bg-emerald-900 text-white px-10 py-5 rounded-[2rem] font-bold text-lg hover:bg-emerald-800 transition-all hover:scale-105 active:scale-95 shadow-xl shadow-emerald-900/20">
                Shop Fresh Now
              </a>
              <button className="bg-white text-stone-900 px-10 py-5 rounded-[2rem] font-bold text-lg border border-stone-200 hover:border-emerald-200 hover:bg-stone-50 transition-all">
                Learn our Story
