import { RootsPage } from './components/RootsPage';
import { PRODUCTS } from './constants';
import { Product, CartItem } from './types';

type View = 'home' | 'lab' | 'vibe' | 'roots';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  const LOGO_URL = "https://images.squarespace-cdn.com/content/v1/66f68f187037746205ed8318/7611ef42-c67d-4180-8742-b7e6140882e3/jaba+tamu+logo.jpg";

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentView]);

  const addToCart = (product: Product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
    ).filter(item => item.quantity > 0));
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(item => item.id !== id));
  };

  const cartCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  const renderView = () => {
    switch(currentView) {
      case 'lab': return <LabPage />;
      case 'vibe': return <VibePage />;
      case 'roots': return <RootsPage />;
      default: return (
        <>
          {/* Hero */}
          <section className="relative pt-48 pb-32 overflow-hidden flex flex-col items-center">
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 -z-10 w-[600px] h-[600px] bg-yellow-500/10 rounded-full blur-[120px] animate-pulse"></div>
            <div className="container mx-auto px-6 text-center space-y-10">
              <div className="inline-flex items-center gap-3 px-6 py-2 bg-white/5 border border-white/10 rounded-full text-stone-300 text-xs font-black tracking-[0.2em] uppercase">
                <span className="flex h-2 w-2 rounded-full bg-green-500 animate-ping"></span>
                Freshly Pressed
              </div>
              <h1 className="text-7xl md:text-9xl font-black text-white leading-[0.9] tracking-tighter">
                THE TASTE OF <br /> 
                <span className="text-brand italic">ENERGY.</span>
              </h1>
              <p className="text-lg text-stone-400 max-w-xl mx-auto font-medium leading-relaxed">
                Elevate your spirit with our signature cold-pressed khat elixirs. Pure focus, zero compromises.
              </p>
              <div className="flex flex-col sm:flex-row items-center justify-center gap-6 pt-6">
                <a href="#shop" className="bg-white text-black px-12 py-5 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-yellow-400 transition-all hover:scale-105">
                  Shop Now
                </a>
                <button 
                  onClick={() => setCurrentView('lab')}
                  className="bg-transparent text-white px-12 py-5 rounded-2xl font-black text-sm uppercase tracking-widest border border-white/20 hover:bg-white/5 transition-all"
                >
                  The Science
                </button>
              </div>
            </div>
          </section>

          {/* Product Section */}
          <section id="shop" className="py-32 bg-[#050505]">
            <div className="container mx-auto px-6">
              <div className="max-w-xl mb-20">
                <h2 className="text-4xl font-black text-white mb-4 uppercase tracking-tighter">The Daily Harvest</h2>
                <div className="h-1 w-20 bg-green-500 rounded-full mb-6"></div>
                <p className="text-stone-500 font-medium">Limited batches pressed daily for maximum potency.</p>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-12 max-w-6xl mx-auto">
                {PRODUCTS.map(product => (
                  <ProductCard key={product.id} product={product} onAdd={addToCart} />
                ))}
              </div>
            </div>
          </section>
        </>
      );
    }
  };

  return (
    <div className="min-h-screen selection:bg-yellow-500 selection:text-black bg-[#0a0a0a]">
      {/* Navigation */}
      <nav className={`fixed top-0 left-0 right-0 z-[70] transition-all duration-500 ${scrolled ? 'py-4' : 'py-8'}`}>
        <div className="container mx-auto px-6">
          <div className={`glass rounded-[2rem] px-6 py-3 flex justify-between items-center transition-all duration-500 ${scrolled ? 'shadow-2xl border-white/10' : 'border-transparent bg-transparent'}`}>
            <button onClick={() => setCurrentView('home')} className="flex items-center gap-4 group">
              <div className="w-12 h-12 rounded-full overflow-hidden border border-white/20 transition-transform group-hover:scale-110">
                <img src={LOGO_URL} alt="JabaTamu Logo" className="w-full h-full object-cover" />
              </div>
              <span className="text-xl font-black tracking-tight text-white hidden sm:block">JabaTamu</span>
            </button>

            <div className="hidden md:flex items-center gap-10 text-xs font-bold uppercase tracking-widest text-stone-400">
              <button onClick={() => setCurrentView('lab')} className={`hover:text-white transition-colors ${currentView === 'lab' ? 'text-green-500' : ''}`}>The Lab</button>
              <button onClick={() => setCurrentView('vibe')} className={`hover:text-white transition-colors ${currentView === 'vibe' ? 'text-orange-500' : ''}`}>The Vibe</button>
              <button onClick={() => setCurrentView('roots')} className={`hover:text-white transition-colors ${currentView === 'roots' ? 'text-yellow-500' : ''}`}>Our Roots</button>
            </div>

            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-3 text-white hover:text-yellow-400 transition-colors group bg-white/5 rounded-2xl"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="8" cy="21" r="1"/><circle cx="19" cy="21" r="1"/><path d="M2.05 2.05h2l2.66 12.42a2 2 0 0 0 2 1.58h9.78a2 2 0 0 0 1.95-1.57l1.65-7.43H5.12"/></svg>
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-green-500 text-black text-[10px] font-black w-5 h-5 flex items-center justify-center rounded-full ring-4 ring-[#0a0a0a]">
                  {cartCount}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Page Content */}
      <main className="animate-in fade-in duration-700">
        {renderView()}
      </main>

      {/* Footer */}
      <footer className="bg-black pt-32 pb-16 border-t border-white/5">
        <div className="container mx-auto px-6">
          <div className="flex flex-col md:flex-row justify-between items-center gap-12 mb-20 text-center md:text-left">
            <div className="space-y-6">
              <div className="flex items-center gap-4 justify-center md:justify-start">
                <div className="w-12 h-12 rounded-full overflow-hidden border border-white/10">
                  <img src={LOGO_URL} alt="JabaTamu Logo" />
                </div>
                <span className="text-2xl font-black text-white italic">JabaTamu</span>
              </div>
              <p className="text-stone-500 max-w-xs font-medium">Brewed with Tradition, Refined with Science.</p>
            </div>
            <div className="flex gap-12 text-xs font-bold uppercase tracking-[0.3em] text-stone-600">
              <button onClick={() => setCurrentView('lab')} className="hover:text-white">The Lab</button>
              <button onClick={() => setCurrentView('vibe')} className="hover:text-white">The Vibe</button>
              <button onClick={() => setCurrentView('roots')} className="hover:text-white">Our Roots</button>
            </div>
          </div>
        </div>
      </footer>

      <Cart 
        isOpen={isCartOpen} 
        items={cartItems} 
        onClose={() => setIsCartOpen(false)}
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
      />
      <AIAssistant />
    </div>
  );
};

export default App;

