            <div className="container mx-auto px-6">
              <div className="flex flex-col md:flex-row justify-between items-end gap-10 mb-24">
                <div className="max-w-xl">
                  <h2 className="text-5xl font-black text-white mb-6 uppercase tracking-tighter leading-none">THE SIGNATURES</h2>
                  <div className="h-1.5 w-24 bg-gradient-to-r from-green-500 to-yellow-500 rounded-full mb-8"></div>
                  <p className="text-stone-500 text-lg font-medium leading-relaxed">
                    Cold-pressed in limited daily quantities to ensure maximum alkaloid retention and flavor clarity.
                  </p>
                </div>
                <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] text-stone-600 border border-white/5 px-6 py-3 rounded-2xl">
                  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="text-green-500"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></symbol><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
                  Certified Organic Sourcing
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-16 max-w-7xl mx-auto">
                {PRODUCTS.map(product => (
                  <ProductCard key={product.id} product={product} onAdd={addToCart} />
                ))}
              </div>
            </div>
          </section>
        </>
      );
    }
