            <div className="flex items-center gap-6">
              <button 
                onClick={navigateToShop}
                className="hidden lg:block bg-white/5 border border-white/10 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest text-white hover:bg-white hover:text-black transition-all"
              >
                Shop
              </button>
              <button 
                onClick={() => setIsCartOpen(true)}
                className="relative p-3.5 text-white hover:text-yellow-400 transition-colors group bg-white/5 rounded-2xl border border-white/5"
