import React, { useState } from 'react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onAdd: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, onAdd }) => {
  const [isAdded, setIsAdded] = useState(false);

  const handleAdd = () => {
    onAdd(product);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  return (
    <div className="group bg-[#111111] rounded-[3rem] border border-white/5 overflow-hidden transition-all duration-700 hover:border-white/20 hover:shadow-[0_40px_80px_rgba(0,0,0,0.6)]">
      <div className="relative aspect-[4/5] overflow-hidden">
        {/* Social Proof Badge */}
        {product.flavor === 'Passion' && (
          <div className="absolute top-8 right-8 z-10 animate-bounce">
            <span className="bg-yellow-400 text-black text-[9px] font-black uppercase tracking-[0.2em] px-4 py-2 rounded-full shadow-2xl">
              Most Popular
            </span>
          </div>
        )}

        <img 
          src={product.image} 
          alt={product.name} 
          className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#111111] via-transparent to-transparent opacity-80"></div>

        <div className="absolute bottom-8 left-8 right-8 flex justify-between items-end">
          <div className="space-y-1">
            <span className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-[0.2em] border backdrop-blur-md ${product.color}`}>
              {product.flavor} Formula
            </span>
          </div>
        </div>
      </div>

      <div className="p-10 md:p-12 space-y-10">
        <div className="space-y-4">
          <div className="flex justify-between items-start">
            <h3 className="text-4xl font-black text-white leading-[0.9] tracking-tighter uppercase">{product.name}</h3>
            <div className="text-2xl font-black text-green-500">KES {product.price}</div>
          </div>
          <p className="text-stone-500 text-sm leading-relaxed font-medium">
            {product.description}
          </p>
        </div>

        <div className="flex flex-wrap gap-4">
          {product.benefits.map(benefit => (
            <div key={benefit} className="flex items-center gap-2">
              <div className="w-1 h-1 bg-green-500 rounded-full"></div>
              <span className="text-[10px] text-stone-400 font-bold uppercase tracking-widest">
                {benefit}
              </span>
            </div>
          ))}
        </div>

        <button 
          onClick={handleAdd}
          disabled={isAdded}
          className={`w-full py-6 rounded-2xl flex items-center justify-center gap-4 font-black uppercase tracking-[0.3em] text-xs transition-all duration-300 ${
            isAdded 
            ? 'bg-green-500 text-black scale-[0.98]' 
            : 'bg-white text-black hover:bg-yellow-400 hover:shadow-[0_15px_30px_rgba(251,191,36,0.15)] active:scale-95'
          }`}
        >
